use strict;
use warnings;

use 5.012000;
use ExtUtils::MakeMaker;

# Probe the host's SysV IPC implementation at configure time.
#
# IPC::Manager ships a SharedMem protocol that uses SysV semaphores and
# shared memory.  On a small number of CPAN tester hosts those primitives
# behave incorrectly (we have observed sporadic EINVAL from semop on
# freshly-created semaphores under perl 5.32 / 5.36 on certain Debian
# kernels), which makes the SharedMem integration tests fail in
# confusing ways.
#
# Rather than blocking the whole distribution from installing on such
# hosts, when the probe fails we surgically disable just the SharedMem
# module: we flip its `$BROKEN_SYSV_IPC` package variable from 0 to 1
# in lib/IPC/Manager/Client/SharedMem.pm.  The module still loads, but
# its _viable() method throws an exception explaining how to recover.
# All other protocols install normally.  The matching test files use
# viable() to detect the disabled state and skip_all themselves, so
# the build still PASSes on these hosts.
#
# This probe uses only core perl SysV builtins (semget / semop / shmget
# / shmread / shmwrite / shmctl / semctl); it never loads or calls into
# IPC::Manager.  A regression in our own SharedMem code therefore
# cannot reach this probe -- only environmental SysV breakage triggers
# the disable.

PROBE_SYSV: {
    last PROBE_SYSV
        unless eval { require IPC::SysV; IPC::SysV->VERSION('2.09'); 1 };

    my $IPC_PRIVATE = IPC::SysV::IPC_PRIVATE();
    my $IPC_CREAT   = IPC::SysV::IPC_CREAT();
    my $IPC_RMID    = IPC::SysV::IPC_RMID();
    my $S_IRUSR     = IPC::SysV::S_IRUSR();
    my $S_IWUSR     = IPC::SysV::S_IWUSR();
    my $mask        = $S_IRUSR | $S_IWUSR | $IPC_CREAT;

    my $LOCK   = pack("s!3", 0, -1, 0);
    my $UNLOCK = pack("s!3", 0,  1, 0);

    my $reason;

    my $dance = sub {
        my $sem_id = semget($IPC_PRIVATE, 1, $mask);
        return "semget failed: $!" unless defined $sem_id;

        unless (semop($sem_id, $UNLOCK)) {
            my $err = "init semop failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        for (1 .. 10) {
            unless (semop($sem_id, $LOCK)) {
                my $err = "lock semop failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
                return $err;
            }
            unless (semop($sem_id, $UNLOCK)) {
                my $err = "unlock semop failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
                return $err;
            }
        }

        my $shm_id = shmget($IPC_PRIVATE, 4096, $mask);
        unless (defined $shm_id) {
            my $err = "shmget failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        my $payload = "ipc-manager-probe-payload";
        unless (shmwrite($shm_id, $payload, 0, length $payload)) {
            my $err = "shmwrite failed: $!";
            shmctl($shm_id, $IPC_RMID, 0);
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        my $buf = '';
        unless (shmread($shm_id, $buf, 0, length $payload)) {
            my $err = "shmread failed: $!";
            shmctl($shm_id, $IPC_RMID, 0);
            semctl($sem_id, 0, $IPC_RMID, 0);
            return $err;
        }

        if ($buf ne $payload) {
            shmctl($shm_id, $IPC_RMID, 0);
            semctl($sem_id, 0, $IPC_RMID, 0);
            return "shmread returned wrong data";
        }

        shmctl($shm_id, $IPC_RMID, 0);
        semctl($sem_id, 0, $IPC_RMID, 0);
        return undef;
    };

    # Single-process dance.
    $reason = $dance->();

    # Cross-fork dance: parent creates the semaphore, the child
    # repeatedly locks/unlocks it, parent reaps and then exercises it
    # again.  Mirrors how IPC::Manager actually uses SysV across
    # forked service processes.
    if (!$reason) {
        my $sem_id = semget($IPC_PRIVATE, 1, $mask);
        if (!defined $sem_id) {
            $reason = "fork-probe semget failed: $!";
        }
        elsif (!semop($sem_id, $UNLOCK)) {
            $reason = "fork-probe init semop failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
        }
        else {
            my $pid = fork;
            if (!defined $pid) {
                $reason = "fork-probe fork failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
            }
            elsif (!$pid) {
                # child
                require POSIX;
                for (1 .. 5) {
                    semop($sem_id, $LOCK)   or POSIX::_exit(2);
                    semop($sem_id, $UNLOCK) or POSIX::_exit(3);
                }
                POSIX::_exit(0);
            }
            else {
                waitpid($pid, 0);
                my $status = $?;
                if ($status) {
                    $reason = "fork-probe child exited non-zero (status=$status)";
                }
                else {
                    for (1 .. 5) {
                        unless (semop($sem_id, $LOCK)) {
                            $reason = "fork-probe parent post-child lock failed: $!";
                            last;
                        }
                        unless (semop($sem_id, $UNLOCK)) {
                            $reason = "fork-probe parent post-child unlock failed: $!";
                            last;
                        }
                    }
                }
                semctl($sem_id, 0, $IPC_RMID, 0);
            }
        }
    }

    # Concurrent-contention dance: parent creates the semaphore,
    # forks several children that all spin on lock/unlock in
    # parallel, and contends on the same semaphore itself.  Some
    # hosts have SysV IPC that only misbehaves under real
    # contention; a single-reader single-writer probe passes but
    # concurrent semop races surface EINVAL.
    if (!$reason) {
        my $N_CHILDREN = 4;
        my $ITERS      = 25;

        my $sem_id = semget($IPC_PRIVATE, 1, $mask);
        if (!defined $sem_id) {
            $reason = "contend-probe semget failed: $!";
        }
        elsif (!semop($sem_id, $UNLOCK)) {
            $reason = "contend-probe init semop failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
        }
        else {
            require POSIX;

            my @pids;
            for (1 .. $N_CHILDREN) {
                my $pid = fork;
                if (!defined $pid) {
                    $reason = "contend-probe fork failed: $!";
                    last;
                }
                if (!$pid) {
                    for (1 .. $ITERS) {
                        semop($sem_id, $LOCK)   or POSIX::_exit(2);
                        semop($sem_id, $UNLOCK) or POSIX::_exit(3);
                    }
                    POSIX::_exit(0);
                }
                push @pids, $pid;
            }

            unless ($reason) {
                for (1 .. $ITERS) {
                    unless (semop($sem_id, $LOCK)) {
                        $reason = "contend-probe parent lock failed: $!";
                        last;
                    }
                    unless (semop($sem_id, $UNLOCK)) {
                        $reason = "contend-probe parent unlock failed: $!";
                        last;
                    }
                }
            }

            for my $pid (@pids) {
                waitpid($pid, 0);
                my $status = $?;
                next if $reason;
                $reason = "contend-probe child exited non-zero (status=$status)"
                    if $status;
            }

            semctl($sem_id, 0, $IPC_RMID, 0);
        }
    }

    # Rapid create/use/destroy dance.  The originally observed
    # failure mode is "sporadic EINVAL from semop on freshly-created
    # semaphores".  This phase churns through many create/init/
    # lock/unlock/destroy cycles to surface that kind of flakiness,
    # which a single-shot probe would miss.
    if (!$reason) {
        for my $iter (1 .. 30) {
            my $sem_id = semget($IPC_PRIVATE, 1, $mask);
            unless (defined $sem_id) {
                $reason = "churn-probe semget iter $iter failed: $!";
                last;
            }
            unless (semop($sem_id, $UNLOCK)) {
                $reason = "churn-probe init semop iter $iter failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
                last;
            }
            unless (semop($sem_id, $LOCK)) {
                $reason = "churn-probe lock iter $iter failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
                last;
            }
            unless (semop($sem_id, $UNLOCK)) {
                $reason = "churn-probe unlock iter $iter failed: $!";
                semctl($sem_id, 0, $IPC_RMID, 0);
                last;
            }
            semctl($sem_id, 0, $IPC_RMID, 0);
        }
    }

    # A. systemd-logind RemoveIPC probe (informational, Linux-only).
    #
    # When logind is configured with RemoveIPC=yes (the default on
    # recent Debian/Ubuntu/RHEL) every SysV IPC object owned by a
    # user is destroyed when that user's last login session ends.
    # CPAN smokers that transition across session boundaries during
    # a test run see their semaphores yanked by the kernel, producing
    # sporadic EINVAL from semop.  Linger (`loginctl enable-linger`)
    # suppresses this cleanup.
    #
    # We can't tell from config alone whether a given run will
    # actually straddle a session boundary, and on interactive
    # developer machines it usually won't.  So phase A is a
    # diagnostic: we record the finding and, if a later gating
    # phase (B or C) trips, include it in the failure reason so
    # the affected user has something actionable to read.
    #
    # systemd-logind is Linux-only, so skip this phase on every
    # other platform -- BSD / macOS / Solaris / AIX / etc. all
    # support SysV IPC but do not have logind.
    my $logind_hint;
    if ($^O eq 'linux') {
        my $remove_ipc;

        my @conf_paths = ('/etc/systemd/logind.conf');
        if (opendir my $dh, '/etc/systemd/logind.conf.d') {
            push @conf_paths, map { "/etc/systemd/logind.conf.d/$_" }
                              grep { /\.conf\z/ } readdir $dh;
            closedir $dh;
        }
        for my $path (@conf_paths) {
            next unless -r $path;
            open my $fh, '<', $path or next;
            while (defined(my $line = <$fh>)) {
                next if $line =~ /^\s*(?:#|$)/;
                if ($line =~ /^\s*RemoveIPC\s*=\s*(\S+)/i) {
                    my $val = lc $1;
                    $remove_ipc = ($val eq 'yes' || $val eq 'true'
                                || $val eq 'on'  || $val eq '1') ? 1 : 0;
                }
            }
            close $fh;
        }

        # If no config said anything but systemd-logind appears to be
        # running, the compiled-in default is RemoveIPC=yes.
        $remove_ipc //= -d '/run/systemd/users' ? 1 : 0;

        if ($remove_ipc) {
            my $uid  = $<;
            my $user = eval { scalar getpwuid($uid) };

            my $linger = 0;
            if ($user && -e "/var/lib/systemd/linger/$user") {
                $linger = 1;
            }
            elsif (-d '/run/systemd/users') {
                local $ENV{LC_ALL} = 'C';
                my $out = eval { `loginctl show-user $uid --property=Linger 2>/dev/null` };
                $linger = 1 if defined $out && $out =~ /Linger\s*=\s*yes/i;
            }

            unless ($linger) {
                $logind_hint = "systemd-logind has RemoveIPC=yes and this user "
                             . "has no linger, so SysV IPC objects will be "
                             . "destroyed when the login session ends "
                             . "(workaround: sudo loginctl enable-linger \$USER)";
            }
        }
    }

    # B. Kernel SysV IPC limit probe (Linux-only).
    #
    # Hosts with absurdly tight SysV IPC limits cannot support the
    # SharedMem protocol even when semop/shmop work in isolation.
    # We require enough capacity for SharedMem's per-spawn pair
    # (one semaphore set, one shared-memory segment, plus transient
    # extras when segments are grown) and a default-sized shm
    # segment (65 536 bytes).
    #
    # The four-integer /proc/sys/kernel/sem layout and the
    # /proc/sys/kernel/shm* files are Linux-specific.  *BSD,
    # macOS, Solaris, AIX, and HP-UX expose comparable tunables
    # via sysctl or kstat in incompatible formats and names, and
    # their defaults are already sufficient for SharedMem, so we
    # simply skip this phase off-Linux rather than try to parse
    # every platform's flavour.
    if (!$reason && $^O eq 'linux') {
        my $read_first_line = sub {
            my ($path) = @_;
            return undef unless -r $path;
            open my $fh, '<', $path or return undef;
            my $line = <$fh>;
            close $fh;
            return undef unless defined $line;
            chomp $line;
            return $line;
        };

        # /proc/sys/kernel/sem: SEMMSL SEMMNS SEMOPM SEMMNI
        if (defined(my $line = $read_first_line->('/proc/sys/kernel/sem'))) {
            my ($semmsl, undef, $semopm, $semmni) = split /\s+/, $line;
            if (defined $semmsl && $semmsl =~ /^\d+$/ && $semmsl < 1) {
                $reason = "kernel SEMMSL=$semmsl is below 1";
            }
            elsif (defined $semopm && $semopm =~ /^\d+$/ && $semopm < 3) {
                $reason = "kernel SEMOPM=$semopm is below required 3";
            }
            elsif (defined $semmni && $semmni =~ /^\d+$/ && $semmni < 8) {
                $reason = "kernel SEMMNI=$semmni is too low to support concurrent SharedMem spawns";
            }
        }

        if (!$reason) {
            for my $spec (
                ['/proc/sys/kernel/shmmni', 8,     'SHMMNI'],
                ['/proc/sys/kernel/shmmax', 65536, 'SHMMAX'],
            ) {
                my ($path, $min, $name) = @$spec;
                my $val = $read_first_line->($path);
                next unless defined $val && $val =~ /^\d+$/;
                if ($val < $min) {
                    $reason = "kernel $name=$val is below required minimum $min";
                    last;
                }
            }
        }
    }

    # C. Persistence probe.
    #
    # Catch-all for anything outside our process that reaps SysV IPC
    # objects: systemd-logind in configurations we didn't detect in
    # phase A, periodic `ipcrm` cronjobs, cgroup/container IPC
    # policies, chroot/jail cleanup, etc.  We create a semaphore,
    # initialise it, sleep briefly, and verify it still works.  If
    # something yanked it, we get EINVAL (or EIDRM) and disable
    # SharedMem.  The sleep is intentionally short -- longer than a
    # fast reaper but well under a Makefile.PL's reasonable budget.
    #
    # Unlike phases A and B, this phase is portable: it only uses
    # the same core semget/semop/semctl builtins the earlier
    # dances already proved functional, so it runs on every SysV-
    # capable platform.  On platforms with no reaper it always
    # passes and adds ~1.5s to configure time.
    if (!$reason) {
        my $sem_id = semget($IPC_PRIVATE, 1, $mask);
        if (!defined $sem_id) {
            $reason = "persist-probe semget failed: $!";
        }
        elsif (!semop($sem_id, $UNLOCK)) {
            $reason = "persist-probe init semop failed: $!";
            semctl($sem_id, 0, $IPC_RMID, 0);
        }
        else {
            select(undef, undef, undef, 1.5);

            if (!semop($sem_id, $LOCK)) {
                $reason = "persist-probe lock-after-wait failed ($!); "
                        . "something outside this process appears to be "
                        . "reaping SysV IPC objects on this host "
                        . "(systemd-logind RemoveIPC, an ipcrm cronjob, "
                        . "a cgroup IPC policy, etc.)";
            }
            elsif (!semop($sem_id, $UNLOCK)) {
                $reason = "persist-probe unlock-after-wait failed: $!";
            }

            semctl($sem_id, 0, $IPC_RMID, 0);
        }
    }

    # If a gating phase failed, append the logind hint if we collected one.
    if ($reason && $logind_hint) {
        $reason .= " [hint: $logind_hint]";
    }

    last PROBE_SYSV unless $reason;

    # Refuse to munge our own source tree.  The released tarball will
    # not contain inc/configure-probe.pl (it is excluded from the
    # GatherDir build), so a developer running `perl Makefile.PL`
    # against the git checkout never gets their lib/ poisoned.
    last PROBE_SYSV if -e 'inc/configure-probe.pl';

    my $target = 'lib/IPC/Manager/Client/SharedMem.pm';
    last PROBE_SYSV unless -f $target;

    open my $in, '<', $target
        or do { warn "Could not open $target to disable SharedMem: $!"; last PROBE_SYSV };
    my $src = do { local $/; <$in> };
    close $in;

    # Flip `our $BROKEN_SYSV_IPC = 0;` to 1 so _viable() throws.
    unless ($src =~ s/^(our \$BROKEN_SYSV_IPC = )0;/${1}1;/m) {
        # Already flipped, or the variable is missing.
        if ($src =~ /\$BROKEN_SYSV_IPC\s*=\s*1\s*;/) {
            last PROBE_SYSV;     # idempotent: nothing to do
        }
        warn "Could not locate \$BROKEN_SYSV_IPC in $target; SharedMem will not be disabled.\n";
        last PROBE_SYSV;
    }

    open my $out, '>', $target
        or do { warn "Could not write $target to disable SharedMem: $!"; last PROBE_SYSV };
    print $out $src;
    close $out;

    print STDOUT <<"EOM";

*** IPC::Manager::Client::SharedMem disabled at install time ***

Your system's SysV IPC implementation appears to be broken:
  $reason

The SharedMem protocol requires working SysV semaphores and shared
memory.  IPC::Manager will install normally and all other protocols
remain available, but IPC::Manager::Client::SharedMem->viable will
throw an exception explaining how to recover.

EOM
}

